1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_PRICE = 60;
3	const DEDUCTIBLE = 100;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const INSURANCE_VALUES: Record<string, number> = {
15	  sword: 1000,
16	  amulet: 600,
17	  staff: 800,
18	  potion: 400,
19	  rune: 250,
20	  moonstone: 250,
21	};
22	
23	function calculateItemPremium(item: any): number {
24	  const base = BASE_PREMIUMS[item.type];
25	  let premium = base;
26	  if (item.cursed) {
27	    premium += base * 0.5;
28	  }
29	  if (item.enchantment >= 5) {
30	    premium += base * 0.3;
31	  }
32	  return premium;
33	}
