35	export function claimOffice(input: any): unknown {
36	  const results: unknown[] = [];
37	  let quoteIndex = 0;
38	  const policies: Array<{ insuranceSum: number; remainingCap: number }> = [];
39	
40	  for (let stepIndex = 0; stepIndex < input.steps.length; stepIndex++) {
41	    const step = input.steps[stepIndex];
42	    if (step.op === "claim") {
43	      const policy = policies[step.policy];
44	      let totalPayout = 0;
45	      for (const damage of step.incident.damages) {
46	        const reimbursement = damage.amount - DEDUCTIBLE;
47	        if (reimbursement > 0) {
48	          totalPayout += reimbursement;
49	        }
50	      }
51	      if (totalPayout > policy.remainingCap) {
52	        totalPayout = policy.remainingCap;
53	      }
54	      policy.remainingCap -= totalPayout;
55	      results.push({ payout: totalPayout, remainingCap: policy.remainingCap });
56	      continue;
57	    }
58	    const items = step.items;
59	    let itemsTotal = 0;
60	    let policyBase = 0;
61	
62	    const typeCounts: Record<string, number> = {};
63	    for (const item of items) {
64	      itemsTotal += calculateItemPremium(item);
65	      policyBase += BASE_PREMIUMS[item.type];
66	      typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
67	    }
68	
69	    for (const type in typeCounts) {
70	      if (typeCounts[type] === 3) {
71	        itemsTotal = itemsTotal - (3 * BASE_PREMIUMS[type]) + BLOCK_OF_THREE_PRICE;
72	      }
73	    }
74	
75	    let policyModifier = 0;
76	    if (input.customer.yearsWithMHPCO >= 2) {
77	      policyModifier -= policyBase * 0.2;
78	    }
79	    policyModifier += policyBase * 0.1;
80	    if (quoteIndex > 0) {
81	      policyModifier -= policyBase * 0.15;
82	    }
83	
84	    const premium = Math.ceil(itemsTotal + policyModifier + PROCESSING_FEE);
85	    results.push({ premium });
86	
87	    let insuranceSum = 0;
88	    for (const item of items) {
89	      insuranceSum += INSURANCE_VALUES[item.type];
90	    }
91	    policies[stepIndex] = { insuranceSum, remainingCap: insuranceSum * 2 };
92	
93	    quoteIndex++;
94	  }
95	
96	  return { results };
97	}
